import {Nav} from './navbar.interface'
@Component({
  selector: 'app-navbar',
  templateUrl: './navbar.component.html',
  styleUrls: ['./navbar.component.scss']
})
export class NavbarComponent {

  active!: string;

  menu: Nav []= [
    { route: '/', title: 'בית', icon: 'home' },


  ];

}
